#include<bits/stdc++.h>using namespace std;int n,vis[60],a[60],cnt=0;int dfs(int selp){    if(cnt==n)return 0;    if(selp==n+1)    {        cnt++;        for(int i=1;i<=n;i++)cout<<a[i]<<" ";        cout<<"\n";        return 0;    }    for(int i=1;i<=n;i++)    {        if(vis[i]==0)        {            if(selp<=2)            {                vis[i]=1;                a[selp]=i;                dfs(selp+1);                vis[i]=0;            }            else if(a[selp-1]+a[selp-2]!=i)            {                vis[i]=1;                a[selp]=i;                dfs(selp+1);                vis[i]=0;            }        }    }}int main(){	int t;	cin>>t;	while(t--){	    cnt=0;	    memset(vis,0,sizeof(vis));	    memset(a,0,sizeof(a));	    cin>>n;	    dfs(1);	}	return 0;}